import React, { useState, useRef, useEffect } from 'react';
import {
    MapPin,
    AlertCircle,
    CheckCircle2,
    Navigation,
    Plane,
} from 'lucide-react';
import { useStore } from '../store/useStore';
import { cn, formatNumber } from '../lib/utils';

type SubTab = 'departure' | 'enroute' | 'arrival' | 'notes';

interface InflightDisplayProps {
    initialSubTab?: SubTab;
}

interface WaypointInput {
    ata: string;
    fuel: string;
}

export const InflightDisplay: React.FC<InflightDisplayProps> = ({ initialSubTab = 'departure' }) => {
    const flightData = useStore((state) => state.flightData);
    const inflightData = useStore((state) => state.inflightData);
    const setInflightData = useStore((state) => state.setInflightData);

    // Initialize local state from inflightData if available during render, not effect.
    // To handle hydration and updates without effect cascades.
    const [activeSubTab, setActiveSubTab] = useState<SubTab>(
        inflightData?.activeSubTab || ((initialSubTab as unknown as string) === 'waypoints' ? 'enroute' : initialSubTab)
    );
    const [waypointInputs, setWaypointInputs] = useState<Record<number, WaypointInput>>(
        inflightData?.waypointInputs || {}
    );
    const [takeoffTime, setTakeoffTime] = useState<string>(
        inflightData?.takeoffTime || ''
    );
    const tacticalRampFuel = (inflightData?.revisedRampFuel || flightData?.rampFuel || '0');
    const taxiFuel = flightData?.taxiFuel || '0';
    const tacticalAtf = (parseInt(tacticalRampFuel) - parseInt(taxiFuel)).toString();
    const actualEzfw = (inflightData?.revisedEzfw || flightData?.ezfw || '0');
    const tacticalAtow = (parseInt(actualEzfw) + parseInt(tacticalAtf)).toString();

    const [atow, setAtow] = useState<string>(
        inflightData?.atow || tacticalAtow
    );
    const [atf, setAtf] = useState<string>(
        inflightData?.atf || tacticalAtf
    );

    // Track the last seen tactical values to detect changes
    const lastTacticalAtow = useRef(tacticalAtow);
    const lastTacticalAtf = useRef(tacticalAtf);

    // Keep local state in sync with tactical planning from Performance tab
    useEffect(() => {
        // If the tactical calculation changed in the Performance tab, 
        // update the Departure tab automatically.
        if (tacticalAtow !== lastTacticalAtow.current) {
            setAtow(tacticalAtow);
            lastTacticalAtow.current = tacticalAtow;
        }
        if (tacticalAtf !== lastTacticalAtf.current) {
            setAtf(tacticalAtf);
            lastTacticalAtf.current = tacticalAtf;
        }
    }, [tacticalAtow, tacticalAtf]);

    // Initial sync if store is empty but tactical values are available
    useEffect(() => {
        if (!inflightData?.atow && tacticalAtow !== '0') {
            setAtow(tacticalAtow);
        }
        if (!inflightData?.atf && tacticalAtf !== '0') {
            setAtf(tacticalAtf);
        }
    }, [tacticalAtow, tacticalAtf, inflightData?.atow, inflightData?.atf]);

    // Update inflightData in store when local state changes
    useEffect(() => {
        if (!flightData) return;
        const isOverMTOW = atow && Number(atow) > Number(flightData.mtow);
        const effectiveAtow = isOverMTOW ? (inflightData?.atow || tacticalAtow) : (atow || tacticalAtow);
        setInflightData({ activeSubTab, waypointInputs, takeoffTime, atow: effectiveAtow, atf });
    }, [activeSubTab, waypointInputs, takeoffTime, atow, atf, setInflightData, flightData, tacticalAtow]);


    const data = inflightData || {
        activeSubTab: 'departure', // This will be overwritten by local state
        waypointInputs: {}, // This will be overwritten by local state
        takeoffTime: '', // This will be overwritten by local state
        departureATIS: '',
        arrivalATIS: '',
        notes: ''
    };

    const [currentTime, setCurrentTime] = useState<string>(new Date().getUTCHours().toString().padStart(2, '0') + new Date().getUTCMinutes().toString().padStart(2, '0'));
    const rowRefs = useRef<Record<number, HTMLTableRowElement | null>>({});

    const calculateEta = (takeoff: string, ctmMinutes: number) => {
        if (!takeoff || takeoff.length < 4) return null;
        const cleanTime = takeoff.replace(':', '');
        if (cleanTime.length !== 4) return null;
        let hh = parseInt(cleanTime.substring(0, 2), 10);
        let mm = parseInt(cleanTime.substring(2, 4), 10);
        if (isNaN(hh) || isNaN(mm)) return null;
        mm += ctmMinutes;
        hh += Math.floor(mm / 60);
        mm %= 60;
        hh %= 24;
        return `${hh.toString().padStart(2, '0')}:${mm.toString().padStart(2, '0')}`;
    };

    const [activeIndex, setActiveIndex] = useState<number>(-1);

    // Sync activeIndex with current time automatically
    useEffect(() => {
        if (!flightData?.waypointEntries) return;
        const nowNum = parseInt(currentTime, 10);
        let foundIndex = -1;
        for (let i = 0; i < flightData.waypointEntries.length; i++) {
            const wp = flightData.waypointEntries[i];
            if (wp.isFir) continue;
            const eta = calculateEta(takeoffTime, wp.stm);
            if (eta) {
                const etaNum = parseInt(eta.replace(':', ''), 10);
                if (etaNum >= nowNum) {
                    foundIndex = i;
                    break;
                }
            }
        }
        if (foundIndex !== -1) {
            setActiveIndex(foundIndex);
        }
    }, [flightData?.waypointEntries, takeoffTime, currentTime]);

    useEffect(() => {
        if (activeSubTab === 'enroute' && activeIndex !== -1 && rowRefs.current[activeIndex]) {
            rowRefs.current[activeIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [activeSubTab, activeIndex]);

    useEffect(() => {
        const interval = setInterval(() => {
            const now = new Date();
            const timeStr = now.getUTCHours().toString().padStart(2, '0') + now.getUTCMinutes().toString().padStart(2, '0');
            setCurrentTime(timeStr);
        }, 60000);
        return () => clearInterval(interval);
    }, []);

    const [prevInitialSubTab, setPrevInitialSubTab] = useState(initialSubTab);
    if (initialSubTab !== prevInitialSubTab) {
        setPrevInitialSubTab(initialSubTab);
        if (initialSubTab) {
            setActiveSubTab((initialSubTab as unknown as string) === 'waypoints' ? 'enroute' : initialSubTab);
        }
    }

    if (!flightData) {
        return (
            <div className="flex-1 flex flex-col items-center justify-center text-slate-500 glass-panel p-8">
                <Navigation className="w-12 h-12 mb-4 opacity-20" />
                <p className="text-sm font-medium">Please load a flight plan in the Flight Init tab first.</p>
            </div>
        );
    }

    const waypointEntries = flightData.waypointEntries || [];

    const handleInputChange = (index: number, field: keyof WaypointInput, value: string) => {
        let finalValue = value;
        if (field === 'ata') {
            const clean = value.replace(/\D/g, '');
            if (clean.length >= 3) {
                finalValue = `${clean.substring(0, 2)}:${clean.substring(2, 4)}`;
            } else {
                finalValue = clean;
            }
        }
        setWaypointInputs(prev => ({
            ...prev,
            [index]: {
                ...(prev[index] || { ata: '', fuel: '' }),
                [field]: finalValue
            }
        }));
    };
    const formatTimeForInput = (timeStr?: string) => {
        if (!timeStr) return '';
        const clean = timeStr.replace(':', '');
        if (clean.length !== 4) return timeStr;
        return `${clean.substring(0, 2)}:${clean.substring(2, 4)}`;
    };

    const diffMinutes = (time1: string, time2: string) => {
        const t1 = time1.replace(':', '');
        const t2 = time2.replace(':', '');
        if (t1.length !== 4 || t2.length !== 4) return 0;
        const h1 = parseInt(t1.substring(0, 2), 10);
        const m1 = parseInt(t1.substring(2, 4), 10);
        const h2 = parseInt(t2.substring(0, 2), 10);
        const m2 = parseInt(t2.substring(2, 4), 10);
        let diff = (h1 * 60 + m1) - (h2 * 60 + m2);
        if (diff < -1200) diff += 1440;
        if (diff > 1200) diff -= 1440;
        return diff;
    };

    const getLocalTime = (zuluTime: string | null | undefined, offsetStr: string): string => {
        if (!zuluTime || zuluTime === '-') return '-';
        const cleanT = zuluTime.replace(':', '');
        if (cleanT.length !== 4) return zuluTime;

        if (!offsetStr || offsetStr.length !== 5) return zuluTime;
        const sign = offsetStr.charAt(0);
        const hrs = parseInt(offsetStr.substring(1, 3), 10);
        const mins = parseInt(offsetStr.substring(3, 5), 10);
        if (isNaN(hrs) || isNaN(mins)) return zuluTime;

        let diffMins = hrs * 60 + mins;
        if (sign === 'M') diffMins = -diffMins;
        else if (sign !== 'P' && sign !== 'Z') return zuluTime;

        const h = parseInt(cleanT.substring(0, 2), 10);
        const m = parseInt(cleanT.substring(2, 4), 10);

        let totalMins = h * 60 + m + diffMins;
        // Handle day wrapping
        while (totalMins < 0) totalMins += 1440;
        while (totalMins >= 1440) totalMins -= 1440;

        const resH = Math.floor(totalMins / 60);
        const resM = totalMins % 60;
        return `${resH.toString().padStart(2, '0')}:${resM.toString().padStart(2, '0')}`;
    };

    let globalEstAta = '';
    let lastAtaIdx = -1;
    for (let j = waypointEntries.length - 1; j >= 0; j--) {
        const ataClean = waypointInputs[j]?.ata?.replace(':', '');
        if (ataClean && ataClean.length === 4) {
            lastAtaIdx = j;
            break;
        }
    }
    if (lastAtaIdx !== -1) {
        const lastWp = waypointEntries[lastAtaIdx];
        const remainingMinutes = flightData.tripTime - lastWp.stm;
        globalEstAta = calculateEta(waypointInputs[lastAtaIdx].ata, remainingMinutes) || '';
    }

    return (
        <div className="h-full flex flex-col pt-0 overflow-hidden">
            {/* Header */}
            <section className="px-2 mb-2 shrink-0 flex items-center justify-between">
                <h3 className="text-md md:text-lg font-bold text-white flex items-center gap-2">
                    <Navigation className="w-5 h-5 text-aviation-accent" />
                    Inflight Management
                </h3>
                <div className="hidden md:flex items-center gap-4 bg-black/40 px-4 py-2 rounded-xl border border-white/5">
                    <div className="flex flex-col text-left">
                        <span className="text-[9px] text-slate-500 font-bold tracking-widest uppercase">Dest Local Time</span>
                        <span className="text-lg font-mono font-bold text-aviation-accent leading-none mt-0.5">{getLocalTime(currentTime, flightData.destTimezoneOffset || '')}</span>
                    </div>
                </div>
            </section>

            <div className="flex-1 flex flex-col gap-4 min-h-0 px-2">
                <div className="flex p-0.5 bg-white/5 rounded-lg border border-white/5 w-fit shrink-0">
                    {['departure', 'enroute', 'arrival', 'notes'].map((tab) => (
                        <button
                            key={tab}
                            onClick={() => setActiveSubTab(tab as SubTab)}
                            className={cn(
                                "px-3 md:px-4 py-1 md:py-1.5 rounded-md text-[9px] md:text-[10px] font-bold uppercase tracking-widest transition-all",
                                activeSubTab === tab
                                    ? "bg-aviation-accent text-black shadow-lg shadow-aviation-accent/20"
                                    : "text-slate-500 hover:text-slate-300"
                            )}
                        >
                            {tab}
                        </button>
                    ))}
                </div>

                <div className="flex-1 glass-panel overflow-hidden flex flex-col min-h-0">
                    {activeSubTab === 'departure' && (
                        <div className="flex-1 p-3 md:p-5 space-y-3 md:space-y-5 overflow-y-auto custom-scrollbar">
                            <div className="flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-3">
                                    <div className="w-7 h-7 md:w-9 md:h-9 rounded-full bg-aviation-success/10 flex items-center justify-center">
                                        <Plane className="w-3.5 h-3.5 md:w-4 md:h-4 text-aviation-success rotate-45" />
                                    </div>
                                    <div>
                                        <h4 className="text-xs md:text-base font-bold text-white">Departure: {flightData.departure}</h4>
                                        <p className="text-[9px] text-slate-500 uppercase tracking-widest">Origin Airport</p>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <span className="text-[8px] md:text-[9px] font-bold text-slate-500 uppercase tracking-widest">STD</span>
                                    <p className="text-md md:text-lg font-mono font-bold text-aviation-warning">
                                        {flightData.std.includes('/') ? `${flightData.std.split('/')[1].substring(0, 2)}:${flightData.std.split('/')[1].substring(2, 4)}` : flightData.std}
                                    </p>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-3 md:gap-4">
                                <div className="space-y-1 md:space-y-2">
                                    <label className="block text-xs font-semibold text-slate-400 mb-1 uppercase tracking-widest">Block Off Time Z</label>
                                    <input
                                        type="time"
                                        value={formatTimeForInput(waypointInputs[-1]?.ata)}
                                        onChange={(e) => setWaypointInputs(prev => ({ ...prev, [-1]: { ...prev[-1], ata: e.target.value.replace(':', '') } }))}
                                        className="w-48 bg-black/40 border border-white/10 rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-sm md:text-base focus:outline-none focus:border-aviation-accent text-white"
                                    />
                                    {(() => {
                                        const blockOff = waypointInputs[-1]?.ata;
                                        const blockOffClean = blockOff?.replace(':', '') || '';
                                        if (blockOffClean.length !== 4) return null;
                                        const stdClean = flightData.std.includes('/') ? flightData.std.split('/')[1] : flightData.std;
                                        const delay = diffMinutes(blockOffClean, stdClean);
                                        return (
                                            <p className={cn("text-[10px] font-bold uppercase", delay > 0 ? "text-aviation-warning" : "text-aviation-success")}>
                                                {delay > 0 ? `Delay: +${delay} min` : `Early: ${Math.abs(delay)} min`}
                                            </p>
                                        );
                                    })()}
                                </div>
                                <div className="space-y-1 md:space-y-2">
                                    <label className="block text-xs font-semibold text-slate-400 mb-1 uppercase tracking-widest">T.O Time Z</label>
                                    <input
                                        type="time"
                                        value={takeoffTime}
                                        onChange={(e) => setTakeoffTime(e.target.value)}
                                        className="w-48 bg-black/40 border border-white/10 rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-sm md:text-base focus:outline-none focus:border-aviation-accent text-white"
                                    />
                                    {takeoffTime && (
                                        <p className="text-[10px] font-bold uppercase text-aviation-accent">
                                            EST ETA: {calculateEta(takeoffTime, flightData.tripTime)} Z
                                        </p>
                                    )}
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-3 md:gap-4">
                                <div className="space-y-1 md:space-y-2">
                                    <label className="block text-xs font-semibold text-slate-400 mb-1 uppercase tracking-widest">
                                        <div className="flex flex-col">
                                            <span>Actual T.O Weight</span>
                                            <span className="text-[8px] text-slate-600 font-normal normal-case whitespace-nowrap -mt-0.5">ETOW: {formatNumber(flightData.etow)}</span>
                                        </div>
                                    </label>
                                    <input
                                        type="text"
                                        inputMode="numeric"
                                        value={formatNumber(atow)}
                                        onChange={(e) => {
                                            const rawValue = e.target.value.replace(/[^\d]/g, '');
                                            setAtow(rawValue);
                                        }}
                                        placeholder={`e.g. ${flightData.etow}`}
                                        className={cn(
                                            "w-48 bg-black/40 border rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-sm md:text-base focus:outline-none focus:border-aviation-accent text-white",
                                            atow && Number(atow) > Number(flightData.mtow) ? "border-red-500/50 bg-red-500/10" : "border-white/10"
                                        )}
                                    />
                                    {atow && Number(atow) > Number(flightData.mtow) && (
                                        <p className="text-[10px] font-bold text-red-500 uppercase mt-1 animate-pulse">
                                            EXCEEDS MTOW! ({formatNumber(flightData.mtow)})
                                        </p>
                                    )}
                                </div>
                                <div className="space-y-1 md:space-y-2">
                                    <label className="block text-xs font-semibold text-slate-400 mb-1 uppercase tracking-widest">
                                        <div className="flex flex-col">
                                            <span>Actual T.O Fuel</span>
                                            <span className="text-[8px] text-slate-600 font-normal normal-case whitespace-nowrap -mt-0.5">Ramp: {formatNumber(flightData.rampFuel)}</span>
                                        </div>
                                    </label>
                                    <input
                                        type="text"
                                        inputMode="numeric"
                                        value={formatNumber(atf)}
                                        onChange={(e) => {
                                            const rawValue = e.target.value.replace(/[^\d]/g, '');
                                            setAtf(rawValue);
                                        }}
                                        placeholder={`e.g. ${flightData.rampFuel}`}
                                        className="w-48 bg-black/40 border border-white/10 rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-sm md:text-base focus:outline-none focus:border-aviation-accent text-white"
                                    />
                                </div>
                            </div>

                            <div className="flex-1 space-y-1 md:space-y-2 min-h-0">
                                <label className="text-[9px] md:text-[10px] font-bold text-slate-500 uppercase tracking-widest">Departure ATIS / CLEARANCE</label>
                                <textarea
                                    value={data.departureATIS || ''}
                                    onChange={(e) => setInflightData({ departureATIS: e.target.value })}
                                    placeholder="ATIS Info D, QNH 1013..."
                                    className="w-full flex-1 bg-black/40 border border-white/10 rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-xs md:text-sm min-h-[80px] focus:outline-none focus:border-aviation-accent resize-none text-white"
                                />
                            </div>
                        </div>
                    )}

                    {activeSubTab === 'enroute' && (
                        <>
                            <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-2 p-2 bg-white/5 border-b border-white/5 shrink-0 text-[9px] md:text-[10px]">
                                    <div className="flex items-center">
                                        <span className="text-slate-500 font-bold uppercase tracking-widest mr-2">ATOW:</span>
                                        {(() => {
                                            const isOverMTOW = atow && Number(atow) > Number(flightData.mtow);
                                            const displayAtow = isOverMTOW ? tacticalAtow : (atow || tacticalAtow);
                                            return (
                                                <div className="flex items-center gap-1.5">
                                                    <span className={cn(
                                                        "font-mono font-bold",
                                                        parseFloat(displayAtow) <= Number(flightData.mlw) ? "text-aviation-success" : "text-white",
                                                        isOverMTOW && "opacity-50"
                                                    )}>
                                                        {formatNumber(displayAtow)}
                                                    </span>
                                                    {isOverMTOW && (
                                                        <span className="text-[8px] text-red-500 font-bold uppercase">(MTOW Exceeded - Using Tactical Planning)</span>
                                                    )}
                                                </div>
                                            );
                                        })()}
                                        {flightData.mlw && (
                                            <>
                                                <div className="w-px h-3 bg-white/10 mx-2"></div>
                                                <span className="text-slate-600 font-mono">MLW: {formatNumber(flightData.mlw)}</span>
                                            </>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="text-slate-500 font-bold uppercase tracking-widest">ATF:</span>
                                        <span className="text-white font-mono font-bold">{formatNumber(atf) || '-'}</span>
                                    </div>
                                </div>

                                {(() => {
                                    if (!flightData) return null;
                                    const actualTF = parseFloat(atf) || Number(flightData.rampFuel);
                                    const isOverMTOW = atow && Number(atow) > Number(flightData.mtow);
                                    const actualTOW = isOverMTOW ? Number(flightData.etow) : (parseFloat(atow) || Number(flightData.mtow));
                                    const mlw = Number(flightData.mlw) || 0;

                                    let mlwWaypointIdx = -1;
                                    let hideBanner = false;
                                    if (mlw > 0) {
                                        if (actualTOW <= mlw) {
                                            hideBanner = true;
                                        } else {
                                            for (let i = 0; i < waypointEntries.length; i++) {
                                                if (waypointEntries[i].isFir) continue;
                                                const burnedFuel = actualTF - (Number(waypointEntries[i].rfob) * 1000);
                                                const estWeight = actualTOW - burnedFuel;
                                                if (estWeight <= mlw) {
                                                    mlwWaypointIdx = i;
                                                    const mlwWpEta = calculateEta(takeoffTime, waypointEntries[i].stm);
                                                    if (mlwWpEta && currentTime && mlwWpEta !== '-' && currentTime !== '-') {
                                                        if (diffMinutes(mlwWpEta, currentTime) <= 0) {
                                                            hideBanner = true;
                                                        }
                                                    }
                                                    break;
                                                }
                                            }
                                        }
                                    }

                                    return (
                                        <>
                                            {mlwWaypointIdx !== -1 && !hideBanner && (
                                                <div className="bg-aviation-warning/10 border-b border-aviation-warning/30 px-4 py-1 flex items-center justify-between shrink-0 z-20">
                                                    <div className="flex items-center gap-2">
                                                        <Plane className="w-3.5 h-3.5 text-aviation-warning -rotate-45" />
                                                        <span className="text-[10px] md:text-xs font-bold text-aviation-warning uppercase tracking-widest">
                                                            Below MLW At: <span className="text-white font-mono">{waypointEntries[mlwWaypointIdx].name}</span>
                                                        </span>
                                                    </div>
                                                    <div className="flex items-center gap-4">
                                                        <div className="flex flex-col items-end">
                                                            <span className="text-[8px] md:text-[9px] text-slate-400 font-bold uppercase tracking-widest leading-tight">Time</span>
                                                            <span className="text-xs md:text-sm font-mono font-bold text-aviation-warning leading-tight">
                                                                {(() => {
                                                                    const mlwWpEta = calculateEta(takeoffTime, waypointEntries[mlwWaypointIdx].stm);
                                                                    if (!mlwWpEta || !currentTime || mlwWpEta === '-' || currentTime === '-') return '--';
                                                                    const minsLeft = diffMinutes(mlwWpEta, currentTime);
                                                                    if (minsLeft <= 0) return '0h 00m'; // Handled by hideBanner, but safe fallback
                                                                    return `${Math.floor(minsLeft / 60)}h ${(minsLeft % 60).toString().padStart(2, '0')}m`;
                                                                })()}
                                                            </span>
                                                        </div>
                                                    </div>
                                                </div>
                                            )}

                                            <div className="flex-1 overflow-auto custom-scrollbar">
                                                <table className="w-full text-left border-collapse min-w-[700px]">
                                                    <thead className="sticky top-0 z-10 bg-[#0a0a0a]">
                                                        <tr className="bg-white/5 border-b border-white/5">
                                                            <th className="px-4 py-1 text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-slate-500">Waypoint</th>
                                                            <th className="px-4 py-1 text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-slate-500">TRK/DIS</th>
                                                            <th className="px-4 py-1 text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-slate-500">PLN ETA</th>
                                                            <th className="px-4 py-1 text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-slate-500">ATA (Z)</th>
                                                            <th className="px-4 py-1 text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-slate-500">PLN Fuel</th>
                                                            <th className="px-4 py-1 text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-slate-500">ACT Fuel</th>
                                                            <th className="px-4 py-1 text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-slate-500">Diff</th>
                                                        </tr>
                                                    </thead>
                                                    <tbody className="divide-y divide-white/5">
                                                        {waypointEntries.map((wp, idx) => {
                                                            const input = waypointInputs[idx] || { ata: '', fuel: '' };
                                                            const isHighlight = idx === activeIndex;
                                                            const plnFuel = wp.rfob;
                                                            const actFuel = parseFloat(input.fuel);
                                                            const diff = !isNaN(actFuel) ? (actFuel - plnFuel).toFixed(1) : null;

                                                            const isMlwWaypoint = idx === mlwWaypointIdx;
                                                            const isEtops = wp.name.includes('ENTRY') || wp.name.includes('EXIT') || wp.name.includes('ETP');

                                                            return (
                                                                <tr
                                                                    key={idx}
                                                                    ref={el => { rowRefs.current[idx] = el; }}
                                                                    className={cn(
                                                                        "transition-colors group border-l-4",
                                                                        isHighlight ? "bg-white/10 border-aviation-accent shadow-md z-10 relative" : "border-transparent hover:bg-white/5",
                                                                        isMlwWaypoint && !isHighlight ? "bg-aviation-warning/10" : "",
                                                                        wp.isFir && !isHighlight ? "bg-aviation-accent/5" : ""
                                                                    )}
                                                                >
                                                                    <td className="px-4 py-2 md:py-3 cursor-pointer" onClick={() => setActiveIndex(idx)}>
                                                                        <div className="flex items-center gap-2">
                                                                            {wp.isFir ? (
                                                                                <div className="flex items-center gap-2 text-aviation-accent">
                                                                                    <MapPin className="w-3 h-3" />
                                                                                    <span className="text-[10px] md:text-xs font-bold uppercase">{wp.name}</span>
                                                                                </div>
                                                                            ) : (
                                                                                <div className="flex items-center gap-2">
                                                                                    {isMlwWaypoint ? <Plane className="w-3 h-3 text-aviation-warning -rotate-45" /> :
                                                                                        wp.isToc ? <CheckCircle2 className="w-3 h-3 text-aviation-success" /> : // Using success for TOC just to differ
                                                                                            wp.isTod ? <AlertCircle className="w-3 h-3 text-aviation-warning" /> :
                                                                                                <Navigation className="w-3 h-3 text-slate-500" />}
                                                                                    <div className="flex flex-col">
                                                                                        <span className={cn("text-xs md:text-sm font-bold font-mono", isEtops ? "text-amber-400" : "text-white")}>{wp.name}</span>
                                                                                        {isMlwWaypoint && (
                                                                                            <span className="text-[8px] font-bold text-aviation-warning uppercase tracking-widest">&lt; MLW</span>
                                                                                        )}
                                                                                        {isEtops && (
                                                                                            <span className="text-[8px] font-bold text-amber-500 uppercase tracking-widest">ETOPS POINT</span>
                                                                                        )}
                                                                                    </div>
                                                                                </div>
                                                                            )}
                                                                        </div>
                                                                    </td>
                                                                    <td className="px-4 py-2 md:py-3">
                                                                        <div className="flex flex-col items-start justify-center font-mono text-[10px] md:text-xs">
                                                                            <span className="text-aviation-accent">{wp.isFir ? '-' : (wp.itt || '-')}</span>
                                                                            {!wp.isFir && wp.dis && (
                                                                                <span className="text-slate-500 text-[8px] md:text-[9px] mt-0.5">{wp.dis} NM</span>
                                                                            )}
                                                                        </div>
                                                                    </td>
                                                                    <td className="px-4 py-2 md:py-3 font-mono text-[10px] md:text-xs text-aviation-warning font-bold">
                                                                        {wp.isFir ? '-' : (calculateEta(takeoffTime, wp.stm) || '-')}
                                                                    </td>
                                                                    <td className="px-4 py-2 md:py-3 relative group/ata">
                                                                        {!wp.isFir && (
                                                                            <div className="flex items-center gap-1">
                                                                                <input
                                                                                    type="text"
                                                                                    placeholder="0000"
                                                                                    value={input.ata}
                                                                                    onChange={(e) => handleInputChange(idx, 'ata', e.target.value)}
                                                                                    className="bg-black/40 border border-white/10 rounded px-2 py-0.5 text-[10px] md:text-xs font-mono text-aviation-accent w-16 focus:outline-none focus:border-aviation-accent/50 text-center"
                                                                                />
                                                                                {(() => {
                                                                                    if (!input.ata || input.ata.replace(':', '').length !== 4) return null;
                                                                                    const plnEta = calculateEta(takeoffTime, wp.stm);
                                                                                    if (!plnEta) return null;
                                                                                    const diff = diffMinutes(input.ata, plnEta);
                                                                                    if (diff === 0) return null;
                                                                                    return (
                                                                                        <span className={cn(
                                                                                            "text-[9px] font-mono font-bold whitespace-nowrap",
                                                                                            diff > 0 ? "text-red-500" : "text-aviation-success"
                                                                                        )}>
                                                                                            {diff > 0 ? `+${diff}` : `-${Math.abs(diff)}`}
                                                                                        </span>
                                                                                    );
                                                                                })()}
                                                                            </div>
                                                                        )}
                                                                    </td>
                                                                    <td className="px-4 py-2 md:py-3 font-mono text-[10px] md:text-xs text-slate-400">
                                                                        {wp.isFir ? '-' : plnFuel.toFixed(1)}
                                                                    </td>
                                                                    <td className="px-4 py-2 md:py-3">
                                                                        {!wp.isFir && (
                                                                            <input
                                                                                type="number"
                                                                                step="0.1"
                                                                                placeholder="0.0"
                                                                                value={input.fuel}
                                                                                onChange={(e) => handleInputChange(idx, 'fuel', e.target.value)}
                                                                                className="bg-black/40 border border-white/10 rounded px-2 py-0.5 text-[10px] md:text-xs font-mono text-white w-16 focus:outline-none focus:border-aviation-accent/50 text-right"
                                                                            />
                                                                        )}
                                                                    </td>
                                                                    <td className={cn(
                                                                        "px-4 py-2 md:py-3 font-mono text-[10px] md:text-xs font-bold",
                                                                        diff === null ? "text-slate-500" : (parseFloat(diff) >= 0 ? "text-aviation-success" : "text-aviation-warning")
                                                                    )}>
                                                                        {!wp.isFir ? (diff ? (parseFloat(diff) > 0 ? `+${diff}` : diff) : '-') : ''}
                                                                    </td>
                                                                </tr>
                                                            );
                                                        })}
                                                    </tbody>
                                                </table>
                                            </div>
                                        </>
                                    );
                                })()}
                            </div>

                            <div className="grid grid-cols-3 gap-2 md:gap-4 py-2 px-4 bg-white/5 border-t border-white/5 shrink-0">
                                {(() => {
                                    const staClean = flightData.sta.includes('/') ? flightData.sta.split('/')[1] : flightData.sta;
                                    const staFmt = flightData.sta.includes('/') ? `${staClean.substring(0, 2)}:${staClean.substring(2, 4)}` : flightData.sta;
                                    const localSta = getLocalTime(staFmt, flightData.destTimezoneOffset || '');
                                    return (
                                        <InflightStat
                                            label="DEST STA"
                                            value={staFmt}
                                            localTime={localSta}
                                            warning
                                        />
                                    );
                                })()}
                                {(() => {
                                    const eta = calculateEta(takeoffTime, flightData.tripTime);
                                    const staClean = flightData.sta.includes('/') ? flightData.sta.split('/')[1] : flightData.sta;
                                    const delay = diffMinutes(eta || '', staClean);
                                    const localEta = getLocalTime(eta, flightData.destTimezoneOffset || '');
                                    return (
                                        <InflightStat
                                            label="DEST ETA"
                                            value={eta || '-'}
                                            localTime={localEta}
                                            error={eta ? delay > 0 : false}
                                            success={eta ? delay <= 0 : false}
                                            info={eta ? (delay === 0 ? "ON TIME" : delay > 0 ? `+${delay} MIN` : `-${Math.abs(delay)} MIN`) : undefined}
                                        />
                                    );
                                })()}
                                {(() => {
                                    const staClean = flightData.sta.includes('/') ? flightData.sta.split('/')[1] : flightData.sta;
                                    const delay = diffMinutes(globalEstAta || '', staClean);
                                    const localAta = getLocalTime(globalEstAta, flightData.destTimezoneOffset || '');
                                    return (
                                        <InflightStat
                                            label="DEST ATA (EST)"
                                            value={globalEstAta || '-'}
                                            localTime={localAta}
                                            error={globalEstAta ? delay > 0 : false}
                                            info={globalEstAta ? (delay === 0 ? "ON TIME" : delay > 0 ? `+${delay} MIN` : `-${Math.abs(delay)} MIN`) : undefined}
                                        />
                                    );
                                })()}
                            </div>
                        </>
                    )}

                    {activeSubTab === 'arrival' && (
                        <div className="flex-1 p-3 md:p-5 space-y-3 md:space-y-5 overflow-y-auto custom-scrollbar text-white">
                            <div className="flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-3">
                                    <div className="w-7 h-7 md:w-9 md:h-9 rounded-full bg-aviation-accent/10 flex items-center justify-center">
                                        <Plane className="w-3.5 h-3.5 md:w-4 md:h-4 text-aviation-accent -rotate-45" />
                                    </div>
                                    <div>
                                        <h4 className="text-xs md:text-base font-bold">Arrival: {flightData.arrival}</h4>
                                        <p className="text-[9px] text-slate-500 uppercase tracking-widest">Destination Airport</p>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <span className="text-[8px] md:text-[9px] font-bold text-slate-500 uppercase tracking-widest">STA</span>
                                    <p className="text-md md:text-lg font-mono font-bold text-aviation-warning">
                                        {flightData.sta.includes('/') ? `${flightData.sta.split('/')[1].substring(0, 2)}:${flightData.sta.split('/')[1].substring(2, 4)}` : flightData.sta}
                                    </p>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-3 md:gap-4">
                                <div className="space-y-1 md:space-y-2">
                                    <label className="block text-xs font-semibold text-slate-400 mb-1 uppercase tracking-widest">Touchdown Time Z</label>
                                    <input
                                        type="time"
                                        value={formatTimeForInput(waypointInputs[998]?.ata || globalEstAta)}
                                        onChange={(e) => handleInputChange(998, 'ata', e.target.value)}
                                        className="w-48 bg-black/40 border border-white/10 rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-sm md:text-base focus:outline-none focus:border-aviation-accent text-white"
                                    />
                                </div>
                                <div className="space-y-1 md:space-y-2">
                                    <label className="block text-xs font-semibold text-slate-400 mb-1 uppercase tracking-widest">Block On Time Z</label>
                                    <input
                                        type="time"
                                        value={formatTimeForInput(waypointInputs[999]?.ata)}
                                        onChange={(e) => handleInputChange(999, 'ata', e.target.value)}
                                        className="w-48 bg-black/40 border border-white/10 rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-sm md:text-base focus:outline-none focus:border-aviation-accent text-white"
                                    />
                                    {(() => {
                                        const blockOn = waypointInputs[999]?.ata;
                                        const blockOnClean = blockOn?.replace(':', '') || '';
                                        if (blockOnClean.length !== 4) return null;
                                        const staClean = flightData.sta.includes('/') ? flightData.sta.split('/')[1] : flightData.sta;
                                        const delay = diffMinutes(blockOnClean, staClean);
                                        return (
                                            <p className={cn("text-[10px] font-bold uppercase", delay > 0 ? "text-aviation-warning text-red-500" : "text-aviation-success")}>
                                                {delay > 0 ? `Delay: ${delay} min` : (delay === 0 ? "Early" : `Early: ${Math.abs(delay)} min`)}
                                            </p>
                                        );
                                    })()}
                                </div>
                            </div>

                            <div className="flex-1 space-y-1 md:space-y-2 min-h-0">
                                <label className="block text-xs font-semibold text-slate-400 mb-1 uppercase tracking-widest">Arrival ATIS</label>
                                <textarea
                                    value={data.arrivalATIS || ''}
                                    onChange={(e) => setInflightData({ arrivalATIS: e.target.value })}
                                    placeholder="ATIS Info X, QNH 1010..."
                                    className="w-full flex-1 bg-black/40 border border-white/10 rounded-lg md:rounded-xl p-2 md:p-3 font-mono text-xs md:text-sm min-h-[80px] focus:outline-none focus:border-aviation-accent resize-none text-white"
                                />
                            </div>
                        </div>
                    )
                    }

                    {
                        activeSubTab === 'notes' && (
                            <div className="flex-1 flex flex-col p-4 md:p-6 min-h-0">
                                <textarea
                                    value={data.notes || ''}
                                    onChange={(e) => setInflightData({ notes: e.target.value })}
                                    placeholder="Jot down ATC clearances, frequencies, or temporary numbers here..."
                                    className="w-full flex-1 bg-transparent text-aviation-warning font-mono text-sm md:text-xl p-4 md:p-6 outline-none resize-none custom-scrollbar"
                                    style={{ lineHeight: '1.6' }}
                                />
                            </div>
                        )}
                </div>
            </div>
        </div>
    );
}

function InflightStat({ label, value, localTime, warning, success, error, info }: { label: string, value: string, localTime?: string, warning?: boolean, success?: boolean, error?: boolean, info?: string }) {
    return (
        <div className="flex flex-col items-center justify-center p-1 relative">
            <span className="text-[8px] md:text-[9px] font-bold text-slate-500 uppercase tracking-widest mb-0.5">{label}</span>
            <div className="flex flex-col items-center">
                <span className={cn(
                    "text-sm md:text-lg font-mono font-bold leading-none",
                    error ? "text-red-500" : success ? "text-aviation-success" : warning ? "text-aviation-warning" : "text-aviation-accent"
                )}>
                    {value}
                </span>
                {localTime && localTime !== '-' && (
                    <span className="text-[10px] md:text-[11px] font-mono font-medium text-slate-400 mt-0.5 leading-none">
                        L: {localTime}
                    </span>
                )}
            </div>
            {info && (
                <span className={cn(
                    "text-[8px] md:text-[9px] font-bold mt-0.5 leading-none",
                    error ? "text-red-500" : success ? "text-aviation-success" : warning ? "text-aviation-warning" : "text-aviation-accent"
                )}>
                    {info}
                </span>
            )}
        </div>
    );
}

import React, { useEffect } from 'react';
import { useStore } from '../store/useStore';
import { Bed, Clock, Users, Layers } from 'lucide-react';
import { cn } from '../lib/utils';
import type { RestData } from '../store/useStore';

const formatTime = (mins: number) => {
    let m = Math.round(mins);
    while (m < 0) m += 1440;
    while (m >= 1440) m -= 1440;
    const hh = Math.floor(m / 60).toString().padStart(2, '0');
    const mm = (m % 60).toString().padStart(2, '0');
    return `${hh}:${mm}`;
};

const parseTime = (timeStr: string) => {
    if (!timeStr) return 0;
    const clean = timeStr.replace(':', '');
    if (clean.length !== 4) return 0;
    return parseInt(clean.substring(0, 2), 10) * 60 + parseInt(clean.substring(2, 4), 10);
};



export const InflightRest: React.FC = () => {
    const flightData = useStore(state => state.flightData);
    const inflightData = useStore(state => state.inflightData);
    const setInflightData = useStore(state => state.setInflightData);

    const restData = inflightData.restData || {
        crewSize: '4',
        pattern: 'Half and Half',
        startTime: '',
        endTime: '',
        buffer: 5
    };

    // Auto-populate times if empty
    useEffect(() => {
        if (!flightData || !inflightData.takeoffTime) return;

        let { startTime, endTime } = restData;
        let needsUpdate = false;

        if (!startTime) {
            const toStr = inflightData.takeoffTime;
            const toMins = parseTime(toStr.replace(':', ''));
            if (toMins > 0 || toStr === '00:00' || toStr === '0000') {
                startTime = formatTime(toMins + 20); // TO + 20 mins
                needsUpdate = true;
            }
        }

        if (!endTime && flightData.tripTime) {
            const toStr = inflightData.takeoffTime;
            const toMins = parseTime(toStr.replace(':', ''));
            if (toMins > 0 || toStr === '00:00' || toStr === '0000') {
                const etaMins = toMins + flightData.tripTime;
                endTime = formatTime(etaMins - 60); // ETA - 1 hour
                needsUpdate = true;
            }
        }

        if (needsUpdate) {
            setInflightData({ restData: { ...restData, startTime, endTime } });
        }
    }, [flightData, inflightData.takeoffTime, restData.startTime, restData.endTime]);

    const updateRestData = (updates: Partial<RestData>) => {
        setInflightData({
            restData: { ...restData, ...updates }
        });
    };

    const handleCrewSizeChange = (size: '3' | '4') => {
        let newPattern = restData.pattern;
        if (size === '3') newPattern = 'Thirds';
        if (size === '4' && newPattern === 'Thirds') newPattern = 'Half and Half';
        updateRestData({ crewSize: size, pattern: newPattern });
    };

    const calculateRestPeriods = () => {
        if (!restData.startTime || !restData.endTime || restData.startTime.length < 4 || restData.endTime.length < 4) return null;

        const startMins = parseTime(restData.startTime);
        let endMins = parseTime(restData.endTime);

        // Handle overnight
        if (endMins < startMins) {
            endMins += 1440;
        }

        const totalMins = endMins - startMins;
        if (totalMins <= 0) return null;

        const buffer = restData.buffer || 0;
        const periods = [];
        let pilotRestStr = '';

        if (restData.crewSize === '4') {
            if (restData.pattern === 'Half and Half') {
                const usable = totalMins - buffer;
                const split = usable / 2;
                pilotRestStr = formatTime(split);

                periods.push({ label: 'Break 1 (First Crew)', start: startMins, end: startMins + split, type: 'rest' });
                periods.push({ label: 'Changeover', start: startMins + split, end: startMins + split + buffer, type: 'buffer' });
                periods.push({ label: 'Break 2 (Second Crew)', start: startMins + split + buffer, end: endMins, type: 'rest' });
            }
            else if (restData.pattern === 'Four Breaks') {
                const usable = totalMins - (3 * buffer);
                const split = usable / 4;
                pilotRestStr = formatTime(split * 2);

                let cur = startMins;
                for (let i = 1; i <= 4; i++) {
                    const label = `Break ${i} (Crew ${i % 2 === 1 ? 'A' : 'B'})`;
                    periods.push({ label, start: cur, end: cur + split, type: 'rest' });
                    cur += split;
                    if (i < 4) {
                        periods.push({ label: 'Changeover', start: cur, end: cur + buffer, type: 'buffer' });
                        cur += buffer;
                    }
                }
            }
            else if (restData.pattern === 'Primary / Relief') {
                const usable = totalMins - (2 * buffer);
                const reliefSplit = usable / 4;
                const primarySplit = usable / 2;
                pilotRestStr = `PRI: ${formatTime(primarySplit)} | RLF: ${formatTime(reliefSplit * 2)}`;

                let cur = startMins;
                periods.push({ label: 'Break 1 (Relief Crew)', start: cur, end: cur + reliefSplit, type: 'rest' });
                cur += reliefSplit;
                periods.push({ label: 'Changeover', start: cur, end: cur + buffer, type: 'buffer' });
                cur += buffer;

                periods.push({ label: 'Break 2 (Primary Crew)', start: cur, end: cur + primarySplit, type: 'rest', highlight: true });
                cur += primarySplit;
                periods.push({ label: 'Changeover', start: cur, end: cur + buffer, type: 'buffer' });
                cur += buffer;

                periods.push({ label: 'Break 3 (Relief Crew)', start: cur, end: endMins, type: 'rest' });
            }
        } else if (restData.crewSize === '3') {
            const usable = totalMins - (2 * buffer);
            const split = usable / 3;
            pilotRestStr = formatTime(split);

            let cur = startMins;
            for (let i = 1; i <= 3; i++) {
                periods.push({ label: `Break ${i}`, start: cur, end: cur + split, type: 'rest' });
                cur += split;
                if (i < 3) {
                    periods.push({ label: 'Changeover', start: cur, end: cur + buffer, type: 'buffer' });
                    cur += buffer;
                }
            }
        }

        return { totalMins, periods, pilotRestStr };
    };

    const result = calculateRestPeriods();

    return (
        <div className="flex-1 flex flex-col gap-3 min-h-0 overflow-y-auto custom-scrollbar p-2 md:p-3">
            {/* Header */}
            <div className="flex items-center gap-2 shrink-0 p-2 glass-panel border border-white/5 rounded-2xl bg-black/40 w-fit">
                <div className="w-7 h-7 rounded-full bg-aviation-accent/10 flex items-center justify-center shrink-0">
                    <Bed className="w-3.5 h-3.5 text-aviation-accent" />
                </div>
                <div>
                    <h2 className="text-sm md:text-base font-bold text-white tracking-tight leading-none mb-0.5">Inflight Rest</h2>
                    <p className="text-[8px] md:text-[9px] font-bold text-slate-500 uppercase tracking-widest leading-none">Crew Rest Calculator</p>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {/* Configuration Panel */}
                <div className="glass-panel border border-white/5 rounded-2xl p-3 md:p-4 space-y-4 bg-black/40">
                    <div className="space-y-4">
                        <div className="flex items-center gap-2 mb-2">
                            <Users className="w-4 h-4 text-slate-400" />
                            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Crew Configuration</h3>
                        </div>

                        <div className="flex gap-1.5 p-1 bg-white/5 rounded-xl border border-white/5 w-full md:w-3/4 max-w-[200px]">
                            {(['3', '4'] as const).map(size => (
                                <button
                                    key={size}
                                    onClick={() => handleCrewSizeChange(size)}
                                    className={cn(
                                        "flex-1 py-1.5 text-[10px] sm:text-xs font-bold rounded-lg transition-all",
                                        restData.crewSize === size ? "bg-aviation-accent text-black shadow-lg" : "text-slate-500 hover:text-slate-300"
                                    )}
                                >
                                    {size} Pilots
                                </button>
                            ))}
                        </div>

                        <div className="space-y-1.5 w-full md:w-3/4 max-w-[150px]">
                            <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest pl-1">Rest Pattern</label>
                            <div className="grid grid-cols-1 gap-1.5">
                                {restData.crewSize === '4' ? (
                                    (['Half and Half', 'Four Breaks', 'Primary / Relief'] as const).map(pattern => (
                                        <button
                                            key={pattern}
                                            onClick={() => updateRestData({ pattern })}
                                            className={cn(
                                                "py-1.5 px-2.5 text-[10px] sm:text-xs font-bold rounded-lg border transition-all text-left",
                                                restData.pattern === pattern
                                                    ? "bg-aviation-accent/10 border-aviation-accent/50 text-aviation-accent"
                                                    : "bg-black/30 border-white/5 text-slate-400 hover:bg-white/5"
                                            )}
                                        >
                                            {pattern}
                                        </button>
                                    ))
                                ) : (
                                    <button
                                        className="py-1.5 px-2.5 text-[10px] sm:text-xs font-bold rounded-lg border bg-aviation-accent/10 border-aviation-accent/50 text-aviation-accent text-left cursor-default col-span-1"
                                    >
                                        Thirds
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Time Inputs Panel */}
                <div className="glass-panel border border-white/5 rounded-2xl p-3 md:p-4 space-y-4 bg-black/40">
                    <div className="flex items-center gap-2 mb-2">
                        <Clock className="w-4 h-4 text-slate-400" />
                        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Time Parameters (Z)</h3>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-1">
                                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest pl-1">Rest Start</label>
                                <input
                                    type="time"
                                    value={restData.startTime.replace(':', '').length === 4 ? `${restData.startTime.replace(':', '').substring(0, 2)}:${restData.startTime.replace(':', '').substring(2, 4)}` : restData.startTime}
                                    onChange={(e) => updateRestData({ startTime: e.target.value.replace(':', '') })}
                                    className="w-full bg-black/40 border border-white/10 rounded-lg p-2 font-mono text-sm focus:outline-none focus:border-aviation-accent text-white transition-all"
                                />
                                <p className="text-[9px] text-slate-600 font-bold uppercase mt-1 pl-1">
                                    {!restData.startTime ? "Auto: T/O + 20m" : ""}
                                </p>
                            </div>
                            <div className="space-y-1">
                                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest pl-1">Rest End</label>
                                <input
                                    type="time"
                                    value={restData.endTime.replace(':', '').length === 4 ? `${restData.endTime.replace(':', '').substring(0, 2)}:${restData.endTime.replace(':', '').substring(2, 4)}` : restData.endTime}
                                    onChange={(e) => updateRestData({ endTime: e.target.value.replace(':', '') })}
                                    className="w-full bg-black/40 border border-white/10 rounded-lg p-2 font-mono text-sm focus:outline-none focus:border-aviation-accent text-white transition-all"
                                />
                                <p className="text-[9px] text-slate-600 font-bold uppercase mt-1 pl-1">
                                    {!restData.endTime ? "Auto: ETA - 1h" : ""}
                                </p>
                            </div>
                        </div>

                        <div className="space-y-1 w-full md:max-w-[140px]">
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest pl-1">Changeover Buffer (Min)</label>
                            <input
                                type="number"
                                min="0"
                                max="60"
                                value={restData.buffer === null || restData.buffer === undefined ? '' : restData.buffer}
                                onChange={(e) => {
                                    const val = e.target.value;
                                    if (val === '') {
                                        updateRestData({ buffer: '' as any }); // Temporarily allow empty string for typing
                                    } else {
                                        updateRestData({ buffer: parseInt(val, 10) });
                                    }
                                }}
                                className="w-full bg-black/40 border border-white/10 rounded-lg p-2 font-mono text-sm focus:outline-none focus:border-aviation-accent text-white transition-all"
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* Schedule View */}
            <div className="mt-2 flex-1 w-full lg:w-3/4">
                {result ? (
                    <div className="space-y-4">
                        <div className="flex flex-col sm:flex-row sm:items-center justify-start gap-4 px-2">
                            <div className="flex items-center gap-2">
                                <Layers className="w-4 h-4 text-aviation-accent" />
                                <h3 className="text-xs font-bold text-white uppercase tracking-widest">Calculated Schedule</h3>
                            </div>
                            <div className="flex flex-wrap items-center gap-2">
                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-white/5 px-3 py-1 rounded-full border border-white/10">
                                    Total Rest Time: <span className="text-white ml-1 font-mono">{formatTime(result.totalMins)}</span>
                                </div>
                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-white/5 px-3 py-1 rounded-full border border-white/10">
                                    Rest By Pilot: <span className="text-aviation-accent ml-1 font-mono">{result.pilotRestStr}</span>
                                </div>
                            </div>
                        </div>

                        <div className="pt-10 pb-4 px-2 w-full max-w-3xl">
                            <div className="relative w-full">
                                {/* Time Markers */}
                                <div className="absolute -top-6 left-0 right-0 w-full h-6 pointer-events-none">
                                    {/* Start marker */}
                                    <div className="absolute top-0 -translate-x-1/2 flex flex-col items-center" style={{ left: '0%' }}>
                                        <span className="text-[10px] sm:text-xs font-mono font-bold text-slate-500">
                                            {formatTime(result.periods[0].start)}
                                        </span>
                                    </div>
                                    {/* End marker */}
                                    <div className="absolute top-0 -translate-x-1/2 flex flex-col items-center" style={{ left: '100%' }}>
                                        <span className="text-[10px] sm:text-xs font-mono font-bold text-aviation-warning">
                                            {formatTime(result.periods[result.periods.length - 1].end)}
                                        </span>
                                    </div>
                                </div>

                                {/* Timeline Bar */}
                                <div className="w-full h-16 md:h-20 flex rounded-xl overflow-hidden border border-white/10 shadow-lg bg-black/60 relative">
                                    {result.periods.map((period, idx) => {
                                        const isBuffer = period.type === 'buffer';
                                        const duration = period.end - period.start;
                                        const widthPerc = (duration / result.totalMins) * 100;

                                        const mainLabel = isBuffer ? "CHG" : period.label.split('(')[0].trim().replace('Break ', 'Rest ');
                                        const subLabel = period.label.includes('(') ? '(' + period.label.split('(')[1] : '';

                                        return (
                                            <div
                                                key={idx}
                                                className={cn(
                                                    "h-full flex flex-col items-center justify-center relative border-r border-black/80 last:border-r-0 transition-colors",
                                                    isBuffer
                                                        ? "bg-slate-800/50"
                                                        : period.highlight
                                                            ? "bg-aviation-accent/50 shadow-[0_0_15px_rgba(56,189,248,0.2)]"
                                                            : "bg-aviation-accent/20 hover:bg-aviation-accent/30"
                                                )}
                                                style={{ width: `${widthPerc}%` }}
                                            >
                                                {/* Hatching for buffer */}
                                                {isBuffer && (
                                                    <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 4px, #fff 4px, #fff 8px)' }}></div>
                                                )}
                                                <div className="z-10 flex flex-col items-center px-1 text-center w-full overflow-hidden">
                                                    <span className={cn(
                                                        "text-[10px] sm:text-xs font-bold uppercase tracking-widest leading-tight whitespace-nowrap overflow-hidden text-ellipsis max-w-full",
                                                        isBuffer ? "text-slate-400" : period.highlight ? "text-white" : "text-white/90"
                                                    )}>
                                                        {mainLabel}
                                                    </span>

                                                    {!isBuffer && (
                                                        <span className="text-xs sm:text-sm font-mono font-bold text-white mt-1">
                                                            {formatTime(period.start)} - {formatTime(period.end)}
                                                        </span>
                                                    )}

                                                    {!isBuffer && subLabel && (
                                                        <span className={cn(
                                                            "text-[8px] sm:text-[10px] tracking-widest uppercase hidden sm:block whitespace-nowrap overflow-hidden text-ellipsis max-w-full mt-0.5",
                                                            period.highlight ? "text-blue-100" : "text-slate-300"
                                                        )}>
                                                            {subLabel}
                                                        </span>
                                                    )}

                                                    {!isBuffer && (
                                                        <span className={cn(
                                                            "text-[9px] sm:text-xs font-mono mt-0.5 hidden md:block",
                                                            period.highlight ? "text-blue-200" : "text-slate-400"
                                                        )}>
                                                            {Math.floor(duration / 60)}h {Math.round(duration % 60).toString().padStart(2, '0')}m
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            {/* Legend */}
                            <div className="mt-5 flex flex-wrap gap-4 px-2 justify-center sm:justify-start">
                                <div className="flex items-center gap-1.5">
                                    <div className="w-3 h-3 rounded bg-aviation-accent/20 border border-white/10"></div>
                                    <span className="text-[9px] text-slate-400 uppercase tracking-widest font-bold">Standard Rest</span>
                                </div>
                                {restData.pattern === 'Primary / Relief' && (
                                    <div className="flex items-center gap-1.5">
                                        <div className="w-3 h-3 rounded bg-aviation-accent/50 border border-white/10 shadow-[0_0_8px_rgba(56,189,248,0.2)]"></div>
                                        <span className="text-[9px] text-slate-400 uppercase tracking-widest font-bold">Primary Rest</span>
                                    </div>
                                )}
                                <div className="flex items-center gap-1.5">
                                    <div className="w-3 h-3 rounded bg-slate-800/50 border border-white/10 relative overflow-hidden">
                                        <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 2px, #fff 2px, #fff 4px)' }}></div>
                                    </div>
                                    <span className="text-[9px] text-slate-400 uppercase tracking-widest font-bold">Changeover Gap</span>
                                </div>
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center h-full text-slate-500 py-12 bg-white/5 rounded-2xl border border-white/5 border-dashed">
                        <Bed className="w-12 h-12 mb-4 opacity-20" />
                        <p className="text-sm font-medium">Enter valid start and end times to calculate the rest schedule.</p>
                        <p className="text-[10px] mt-2 uppercase tracking-widest opacity-50">Or ensure Flight Init data is loaded for auto-population</p>
                    </div>
                )}
            </div>
        </div >
    );
};

